def pdef_rule(m, i, tp):
    if tp not in m.T or (i, tp) not in m.ZPOS:
        return Constraint.Skip
    return m.p[i, tp] == m.x[i, tp - 1] - m.x[i, tp]
model.pdef = Constraint(model.I, model.TP, rule=pdef_rule)

def cdef_rule(m, i, tp):
