model.retirem1 = Constraint(model.M, model.T, rule=retirem1_rule)

def cbal_rule(m, tp):
    return sum(m.c[i, tp] for i in m.I if (i, tp) in m.ZPOS) + m.r[tp] == m.cflow[tp]
model.cbal = Constraint(model.T, rule=cbal_rule)

def tppdef_rule(m, n):
    ord_t = {t: k for k, t in enumerate(m.T, start=1)}
    return m.tpp[n] == sum(ord_t[t] * m.p[n, t] for t in m.T if (n, t) in m.ZPOS)
model.tppdef = Constraint(model.N, rule=tppdef_rule)

def lowal_rule(m, n):
    return m.wallo[n] * sum(m.x[n, ts] for ts in m.TS) <= m.tpp[n]
model.lowal = Constraint(model.N, rule=lowal_rule)

def upwal_rule(m, n):
    return m.walup[n] * sum(m.x[n, ts] for ts in m.TS) >= m.tpp[n]
model.upwal = Constraint(model.N, rule=upwal_rule)

def seq1_rule(m, tp):
    return sum(m.z[i, tp] for i in m.I if (i, tp) in m.ZPOS) == 1.0
model.seq1 = Constraint(model.T, rule=seq1_rule)

def seq2_rule(m, i, tp):
    TL = list(m.TL)[0]
    if tp not in m.T or tp == TL or (i, tp) not in m.ZPOS:
        return Constraint.Skip
    return m.y[i, tp] >= m.y[i, tp + 1]
model.seq2 = Constraint(model.I, model.TP, rule=seq2_rule)

def ydef_rule(m, i, tp):
    if tp not in m.T or (i, tp) not in m.ZPOS:
        return Constraint.Skip
    I_list = list(m.I)
    idx = I_list.index(i)
    if idx < 1:
        return m.y[i, tp] == m.z[i, tp]
    prev_i = I_list[idx - 1]
    return m.y[i, tp] == m.y[prev_i, tp] + m.z[i, tp]
model.ydef = Constraint(model.I, model.TP, rule=ydef_rule)

def tindef1_rule(m, i):
    return sum(m.x[i, ts] for ts in m.TS) <= m.tin[i] * m.bign
model.tindef1 = Constraint(model.I, rule=tindef1_rule)

def tindef2_rule(m, i):
    return sum(m.x[i, ts] for ts in m.TS) >= m.tin[i] * m.smalln
model.tindef2 = Constraint(model.I, rule=tindef2_rule)

def ncon_rule(m):
